// ─── Seed Functions ───────────────────────────────────────────────────────────


async function seedInvoices() {
  const { rows } = await pool.query('SELECT COUNT(*) FROM invoices');
  if (parseInt(rows[0].count) > 0) { console.log('[seed] invoices: already seeded'); return; }
  console.log('[seed] seeding invoices...');
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    for (const inv of INVOICES) {
      await client.query(
        `INSERT INTO invoices (id,company,date,total,paid,status,dept)
         VALUES ($1,$2,$3,$4,$5,$6,$7) ON CONFLICT (id) DO NOTHING`,
        [inv.id,inv.company,toIso(inv.date),inv.total,inv.paid,inv.status,inv.dept]
      );
    }
    await client.query('COMMIT');
    console.log(`[seed] invoices: inserted ${INVOICES.length} rows`);
  } catch(e) { await client.query('ROLLBACK'); console.error('[seed] invoices error:', e.message); }
  finally { client.release(); }
}

async function seedSessions() {
  const { rows } = await pool.query('SELECT COUNT(*) FROM sessions');
  if (parseInt(rows[0].count) > 0) { console.log('[seed] sessions: already seeded'); return; }
  console.log('[seed] seeding sessions...');
  const client = await pool.connect();
  try {
    await client.query('ALTER TABLE sessions DROP CONSTRAINT IF EXISTS sessions_patient_id_fkey');
    await client.query('BEGIN');
    for (const s of SESSIONS) {
      await client.query(
        `INSERT INTO sessions (id,patient_id,dept,doctor,date,notes,amount,paid,debt)
         VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9) ON CONFLICT (id) DO NOTHING`,
        [s.id,s.pid,s.dept,s.doc||null,toIso(s.date),s.notes,s.amount,s.paid,s.debt]
      );
      for (const ref of (s.labRefs||[])) {
        if (ref.trim()) {
          await client.query(
            `INSERT INTO session_lab_refs (session_id,test_name) VALUES ($1,$2)`,
            [s.id, ref]
          );
        }
      }
    }
    await client.query(`SELECT setval('sessions_id_seq', (SELECT MAX(id) FROM sessions))`);
    await client.query('COMMIT');
    console.log(`[seed] sessions: inserted ${SESSIONS.length} rows`);
  } catch(e) { await client.query('ROLLBACK'); console.error('[seed] sessions error:', e.message); }
  finally { client.release(); }
}

async function seedDrawerTransactions() {
  const { rows } = await pool.query('SELECT COUNT(*) FROM drawer_transactions');
  const existingCount = parseInt(rows[0].count);
  if (existingCount >= 10) { console.log('[seed] drawer_transactions: already seeded'); return; }
  console.log('[seed] seeding drawer_transactions...');
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const labTxs = LAB_DRAWER_TXS.map(t => ({...t, dept:'lab'}));
    const rehabTxs = REHAB_DRAWER_TXS.map(t => ({...t, dept:'rehab'}));
    const allTxs = [...labTxs, ...rehabTxs];
    for (const tx of allTxs) {
      await client.query(
        `INSERT INTO drawer_transactions (id,dept,type,title,category,amount,tx_date,balance_after)
         VALUES ($1,$2,$3,$4,$5,$6,$7,$8) ON CONFLICT (id) DO NOTHING`,
        [tx.id,tx.dept,tx.type,tx.title,tx.cat,tx.amount,toIso(tx.date),0]
      );
    }
    await client.query(`SELECT setval('drawer_transactions_id_seq', (SELECT MAX(id) FROM drawer_transactions))`);
    await client.query('COMMIT');
    console.log(`[seed] drawer_transactions: inserted ${allTxs.length} rows`);
  } catch(e) { await client.query('ROLLBACK'); console.error('[seed] drawer_transactions error:', e.message); }
  finally { client.release(); }
}

