async function seedDiagnoses() {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    let inserted = 0;
    for (const d of SURGERY_DIAGNOSES_SEED) {
      const { rowCount } = await client.query(
        `INSERT INTO diagnoses_catalog (code,name,category,dept)
         SELECT $1::text,$2::text,$3::text,$4::text
         WHERE NOT EXISTS (SELECT 1 FROM diagnoses_catalog WHERE name=$2::text AND dept=$4::text)`,
        [d.code, d.name, d.category, d.dept]
      );
      inserted += rowCount;
    }
    await client.query('COMMIT');
    if (inserted > 0) console.log(`[seed] diagnoses_catalog: inserted ${inserted} new entries`);
  } catch(e) { await client.query('ROLLBACK'); console.error('[seed] diagnoses error:', e.message); }
  finally { client.release(); }
}

async function seedAdminAccount() {
  const { rows } = await pool.query('SELECT COUNT(*) FROM admin_accounts');
  if (parseInt(rows[0].count) > 0) { console.log('[seed] admin_accounts: already seeded'); return; }
  const hash = await bcrypt.hash('1234', 10);
  await pool.query(
    `INSERT INTO admin_accounts (username, password_hash, display_name) VALUES ($1,$2,$3)`,
    ['admin', hash, 'مدير النظام']
  );
  console.log('[seed] admin_accounts: inserted default admin (admin/1234)');
}

export async function seedAll() {
  console.log('[seed] starting...');
  // Only seed catalog/reference data — never operational/transactional data
  // lab_tests and rad_catalog are managed exclusively via the UI/database — no hardcoded seed
  await seedAdminAccount();
  await seedDiagnoses();
  // seedInvoices(), seedSessions(), seedDrawerTransactions() intentionally removed:
  // the system has been cleared for live operation. Test data must not be re-injected.
  console.log('[seed] complete.');
}
